kernel void q4mv_spec_mg_f16io_resadd(
    device const uint8_t* packed_nibs [[buffer(0)]],
    device const ushort*  scales      [[buffer(1)]],
    device const ushort*  biases      [[buffer(2)]],
    device const half*    input       [[buffer(3)]],
    device float*         residual    [[buffer(4)]],
    constant QMVDims&     dims        [[buffer(5)]],
    uint tgid [[threadgroup_position_in_grid]],
    uint tid  [[thread_index_in_threadgroup]])
{
    constexpr uint K = SPEC_INTER_K;
    constexpr uint group_size = SPEC_GS;
    static_assert(K % 32 == 0,
        "K must be SIMD-aligned.");
    static_assert(K % group_size == 0,
        "K must be a multiple of group_size.");
    static_assert(group_size % 8 == 0,
        "Group size must be 8-column-aligned "
        "for uint32 boundary alignment.");
    static_assert(K >= 256,
        "K must be >= 256 for Q4 uint32 path.");
    static_assert(K % 512 == 0,
        "K must be divisible by 512 "
        "for cooperative TG load.");
    static_assert(K <= 12288,
        "K must fit in 24 KB threadgroup memory.");
    const uint M = dims.M;

    // Cache input in threadgroup memory.
    threadgroup half tg_input[K];
    constexpr uint elems_per_thread = K / 512;
    for (uint j = 0; j < elems_per_thread; j++) {
        tg_input[tid * elems_per_thread + j] =
            input[tid * elems_per_thread + j];
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint simdgroup_idx = tid / 32;
    const uint lane = tid % 32;
    const uint row0 = tgid * 32 + simdgroup_idx * 2;
    const uint row1 = row0 + 1;

    const bool row0_valid = row0 < M;
    const bool row1_valid = row1 < M;

    constexpr uint groups_per_row = K / group_size;
    constexpr uint nibble_bytes_per_row = K / 2;
    constexpr uint words_per_row = K / 8;
    constexpr uint uint32s_per_lane = words_per_row / 32;

    const uint safe_row0 = min(row0, M - 1);
    const uint safe_row1 = min(row1, M - 1);

    device const uint32_t* w32_r0 =
        (device const uint32_t*)(
            packed_nibs + safe_row0 * nibble_bytes_per_row);
    device const uint32_t* w32_r1 =
        (device const uint32_t*)(
            packed_nibs + safe_row1 * nibble_bytes_per_row);

    float acc0 = 0.0f, acc1 = 0.0f;

    // Interleaved access with per-word group accumulation.
    #pragma clang loop unroll(disable)
    for (uint w = 0; w < uint32s_per_lane; w++) {
        const uint word_idx = w * 32 + lane;
        const uint col_base = word_idx * 8;
        const uint grp = col_base / group_size;

        const uint32_t word0 = w32_r0[word_idx];
        const uint32_t word1 = w32_r1[word_idx];

        float nd0 = 0.0f, nd1 = 0.0f, gs = 0.0f;
        for (uint ni = 0; ni < 8; ni++) {
            const float x = float(tg_input[col_base + ni]);
            nd0 += float((word0 >> (ni * 4)) & 0xFu) * x;
            nd1 += float((word1 >> (ni * 4)) & 0xFu) * x;
            gs += x;
        }

        const uint sc0 =
            safe_row0 * groups_per_row + grp;
        const uint sc1 =
            safe_row1 * groups_per_row + grp;
        acc0 += bf16_to_f32(scales[sc0]) * nd0
              + bf16_to_f32(biases[sc0]) * gs;
        acc1 += bf16_to_f32(scales[sc1]) * nd1
              + bf16_to_f32(biases[sc1]) * gs;
    }

    acc0 = simd_sum(acc0);
    acc1 = simd_sum(acc1);

    if (lane == 0) {
        if (row0_valid) residual[row0] += bf16_round(acc0);
        if (row1_valid) residual[row1] += bf16_round(acc1);
    }
}

// ====================================================================
// Kernel 6: q4mv_spec_fused_pair_silu_f16io — gate/up + SiLU fused
// ====================================================================
/// Fused gate+up projection with SiLU activation and elementwise
/// multiply: output[row] = silu(gate_row) * up_row.  Eliminates
/// the separate SiLU+elementwise_mul dispatch and two barriers
/// per block.
///
/// Uses 1 row per simdgroup (not 2) to keep register pressure
/// low enough for max_threads >= 512 despite the extra exp()
/// in the SiLU output stage.
///

kernel void gqa_attention_fused_f16io_tg(
    device const half*    Q          [[buffer(0)]],
    device half*          k_cache    [[buffer(1)]],
    device half*          v_cache    [[buffer(2)]],
    device half*          output     [[buffer(3)]],
    device const half*    K_raw      [[buffer(4)]],
    device const half*    V_raw      [[buffer(5)]],
    device const float*   q_norm_sc  [[buffer(6)]],
    device const float*   k_norm_sc  [[buffer(7)]],
    constant GQAFusedDims& dims      [[buffer(8)]],
    uint tgid [[threadgroup_position_in_grid]],
    uint tid  [[thread_index_in_threadgroup]])
{
    const uint THREADS = 256;
    const uint SIMD_SIZE = 32;
    const uint NUM_SIMD_GROUPS = THREADS / SIMD_SIZE;
    const uint TG_SEQ_MAX = 1024;
    const uint head = tgid;

    if (head >= dims.num_query_heads) return;

    const uint kv_head = head / dims.heads_per_kv_group;
    const uint head_dim = dims.head_dim;
    const uint seq_len = dims.seq_len;
    const uint max_ctx = dims.max_context_length;
    const uint position = dims.position;

    if (seq_len > TG_SEQ_MAX) return;

    const uint simd_group = tid / SIMD_SIZE;
    const uint simd_lane = tid % SIMD_SIZE;

    const uint kv_stride = max_ctx * head_dim;
    device half* kc = k_cache + kv_head * kv_stride;
    device half* vc = v_cache + kv_head * kv_stride;

    const float inv_sqrt_d = rsqrt(float(head_dim));

    threadgroup float shared_buf[256];
    threadgroup float tg_scores[TG_SEQ_MAX];

    // ── Phase 1: Q — load, per-head RMSNorm, RoPE ──────────
    float q_val = (tid < head_dim)
        ? float(Q[head * head_dim + tid]) : 0.0f;

    // Sum of squares reduction for Q RMSNorm.
    float q_sq = q_val * q_val;
    float q_warp_sq = simd_sum(q_sq);
    if (simd_lane == 0) {
        shared_buf[simd_group] = q_warp_sq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint active_warps = (head_dim + 31) / 32;
    float q_total = 0.0f;
    for (uint i = 0; i < active_warps; i++) {
        q_total += shared_buf[i];
    }
    const float q_rms =
        rsqrt(q_total / float(head_dim) + dims.eps);

    // Normalize and scale Q.
    if (tid < head_dim) {
        q_val = q_val * q_rms * float(q_norm_sc[tid]);
    }
    shared_buf[tid] = q_val;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // RoPE on Q: consecutive-pair rotation.
    if (tid < head_dim && (tid % 2 == 0)) {
        const uint pair = tid / 2;
        const float exp2_arg =
            -float(2 * pair) / float(head_dim)
            * log2(dims.rope_theta);
        const float theta_i = exp2(exp2_arg);
        const float angle = float(position) * theta_i;
        const float cv = cos(angle);
        const float sv = sin(angle);
        const float a = shared_buf[tid];
        const float b = shared_buf[tid + 1];
        shared_buf[tid]     = a * cv - b * sv;
        shared_buf[tid + 1] = a * sv + b * cv;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    // shared_buf[0..head_dim-1] = Q after norm + RoPE.

    // ── Phase 2: K — norm + RoPE → k_cache; V → v_cache ────
    device const half* kr = K_raw + kv_head * head_dim;
    device const half* vr = V_raw + kv_head * head_dim;

    float k_val = (tid < head_dim)
        ? float(kr[tid]) : 0.0f;

    // K RMSNorm reduction — use tg_scores[0..7] as scratch.
    float k_sq = k_val * k_val;
    float k_warp_sq = simd_sum(k_sq);
    if (simd_lane == 0) {
        tg_scores[simd_group] = k_warp_sq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float k_total = 0.0f;
    for (uint i = 0; i < active_warps; i++) {
        k_total += tg_scores[i];
    }
    const float k_rms =
        rsqrt(k_total / float(head_dim) + dims.eps);

    // Normalize, scale K, store for RoPE pair access.
    float k_normed = 0.0f;
    if (tid < head_dim) {
        k_normed = k_val * k_rms * float(k_norm_sc[tid]);
    }
    tg_scores[tid] = k_normed;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // RoPE on K, write to k_cache at current position.
    if (tid < head_dim && (tid % 2 == 0)) {
        const uint pair = tid / 2;
        const float exp2_arg =
            -float(2 * pair) / float(head_dim)
            * log2(dims.rope_theta);
        const float theta_i = exp2(exp2_arg);
        const float angle = float(position) * theta_i;
        const float cv = cos(angle);
        const float sv = sin(angle);
        const float a = tg_scores[tid];
        const float b = tg_scores[tid + 1];
        kc[position * head_dim + tid] =
            half(a * cv - b * sv);
        kc[position * head_dim + tid + 1] =
            half(a * sv + b * cv);
    }

    // Copy V to v_cache at current position.
    if (tid < head_dim) {
        vc[position * head_dim + tid] = vr[tid];
    }

    // Ensure k_cache/v_cache writes are visible within TG.
    threadgroup_barrier(
        mem_flags::mem_device
        | mem_flags::mem_threadgroup
    );

    // ── Phase 3: Attention scores Q·K (SIMD-cooperative) ───
    // Each SIMD group computes one dot product cooperatively:
    // 32 lanes split head_dim (64 / 32 = 2 elements each),
    // then simd_sum reduces.  8 SIMD groups process 8 tokens
    // per iteration — all 256 threads active.
    for (uint t = simd_group; t < seq_len;
         t += NUM_SIMD_GROUPS)
    {
        float partial = 0.0f;
        for (uint d = simd_lane; d < head_dim;
             d += SIMD_SIZE)
        {
            partial += shared_buf[d]
                * float(kc[t * head_dim + d]);
        }
        const float dot = simd_sum(partial);
        if (simd_lane == 0) {
            tg_scores[t] = dot * inv_sqrt_d;
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // ── Phase 4: Softmax — max, exp, sum, normalize ─────────
    float local_max = -INFINITY;
    for (uint t = tid; t < seq_len; t += THREADS) {
        local_max = max(local_max, tg_scores[t]);
    }
    const float warp_max = simd_max(local_max);
    if (simd_lane == 0) {
        shared_buf[simd_group] = warp_max;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float max_score = shared_buf[0];
    for (uint i = 1; i < NUM_SIMD_GROUPS; i++) {
        max_score = max(max_score, shared_buf[i]);
    }

    float local_sum = 0.0f;
    for (uint t = tid; t < seq_len; t += THREADS) {
        const float e = exp(tg_scores[t] - max_score);
        tg_scores[t] = e;
        local_sum += e;
    }
    const float warp_sum = simd_sum(local_sum);
    if (simd_lane == 0) {
        shared_buf[simd_group] = warp_sum;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float sum_exp = shared_buf[0];
    for (uint i = 1; i < NUM_SIMD_GROUPS; i++) {
        sum_exp += shared_buf[i];
    }

    for (uint t = tid; t < seq_len; t += THREADS) {
        tg_scores[t] /= sum_exp;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // ── Phase 5: Weighted V sum (SIMD-cooperative) ──────────
    // Each SIMD group handles one output dimension: 32 lanes
    // split seq_len, then simd_sum reduces.  8 SIMD groups
    // process 8 dimensions per iteration (64 / 8 = 8 iters).
    // All 256 threads active vs only 64 in the per-thread
    // version.
    for (uint d = simd_group; d < head_dim;
         d += NUM_SIMD_GROUPS)
    {
        float partial = 0.0f;
        for (uint t = simd_lane; t < seq_len;
             t += SIMD_SIZE)
        {
            partial += tg_scores[t]
                * float(vc[t * head_dim + d]);
        }
        const float accum = simd_sum(partial);
        if (simd_lane == 0) {
            output[head * head_dim + d] = half(accum);
        }
    }
}

// ============================================================================
// Fused SiLU + Elementwise Mul f16
// ============================================================================

/// Fused SiLU + elementwise multiply with f16 input and f16 output.
///   output[i] = silu(gate[i]) * up[i]
///             = gate[i] * sigmoid(gate[i]) * up[i]
///
/// Internal accumulation stays f32 for precision.
///
/// Dispatch: 1D, count = total elements.

fn dispatchQ4MVf16ioResadd(
    device: *const metal.Device,
    encoder: objc.Object,
    q4_buffer: metal.Q4Buffer,
    input_buffer: objc.Object,
    residual_buffer: objc.Object,
    dims: QMVDims,
) void {
    std.debug.assert(dims.M > 0);
    std.debug.assert(dims.K > 0);
    std.debug.assert(dims.K % 32 == 0);
    std.debug.assert(dims.group_size > 0);
    std.debug.assert(q4_buffer.packed_count > 0);

    // Select single-group (hidden) or multi-group (inter)
    // pipeline based on K dimension.
    const use_sg =
        if (device.spec_q4mv_f16io_resadd) |s|
            s.max_threads_per_group >= 512 and
                dims.K == device.spec_q4_hidden_K
        else
            false;
    const use_mg =
        if (device.spec_q4mv_mg_f16io_resadd) |s|
            s.max_threads_per_group >= 512 and
                dims.K == device.spec_q4_inter_K
        else
            false;
    const pipeline = if (use_sg)
        device.spec_q4mv_f16io_resadd.?
    else if (use_mg)
        device.spec_q4mv_mg_f16io_resadd.?
    else
        unreachable; // Q4 resadd requires specialized pipelines.

    // Batch-bind indices 0-4 (Q4 + input + residual)
    // in a single ObjC call.
    const ptrs = [5]?*anyopaque{
        q4_buffer.obj.value, q4_buffer.obj.value,
        q4_buffer.obj.value, input_buffer.value,
        residual_buffer.value,
    };
    const offsets = [5]c_ulong{
        0,
        @as(c_ulong, q4_buffer.scaleOffset()),
        @as(c_ulong, q4_buffer.biasOffset()),
        0,
        0,
    };
    const range = [2]c_ulong{ 0, 5 };
    encoder.msgSend(
        void,
        "setBuffers:offsets:withRange:",
        .{
            @as(*const anyopaque, @ptrCast(&ptrs)),
            @as(*const anyopaque, @ptrCast(&offsets)),
            @as([2]c_ulong, range),
        },
    );
    metal.setBytes(encoder, QMVDims, &dims, 5);

    const rows_per_tg: u32 = 32;
    const threads_per_tg: u32 = 512;
    const threadgroups =
        (dims.M + rows_per_tg - 1) / rows_per_tg;
    const grid = metal.MTLSize{
        .width = @as(c_ulong, threadgroups),
        .height = 1,
        .depth = 1,
    };
    const group = metal.MTLSize{
        .width = @as(c_ulong, threads_per_tg),
        .height = 1,
        .depth = 1,
    };
    device.dispatchCustom(encoder, pipeline, grid, group);
}

/// Dispatch Q4 fused-pair QMV: f16 input, two f16 outputs.
/// Two Q4 weight matrices share the same input vector.
/// buffer(0-2): Q4 A, buffer(3): input, buffer(4): output A,
/// buffer(5-7): Q4 B, buffer(8): output B, buffer(9): dims.
fn dispatchQ4MVFusedPairf16io(
    device: *const metal.Device,

fn encodeMLPHalf(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    const mlp_qmv = QMVDims{
        .M = Config.intermediate_size,
        .K = Config.hidden_size,
        .group_size = Config.group_size,
    };
    // Gate and up projections share the same input and dims.
    // Best path: fuse FFN-RMSNorm + gate+up+SiLU into a
    // single kernel — saves 2 dispatches + 2 barriers per
    // block by reading the f32 residual directly.
    const can_fuse = comptime (Config.hidden_size % Config.group_size == 0) and
        (Config.hidden_size <= 6144) and
        (Config.hidden_size >= 256) and
        (Config.hidden_size / 32 <= Config.group_size);
    // Fused norm needs K <= 4096 for threadgroup memory.
    const can_fuse_norm = can_fuse and
        comptime (Config.hidden_size <= 4096);
    const use_fused_norm_silu =
        if (comptime Config.quant_format == .q4_mlx)
            can_fuse_norm and
                device.spec_q4mv_fused_norm_pair_silu_f16io !=
                    null and
                device.spec_q4mv_fused_norm_pair_silu_f16io.?
                    .max_threads_per_group >= 512 and
                mlp_qmv.K == device.spec_q4_hidden_K
        else
            can_fuse_norm and
                device.spec_qmv_fused_norm_pair_silu_f16io !=
                    null and
                device.spec_qmv_fused_norm_pair_silu_f16io.?
                    .max_threads_per_group >= 512 and
                mlp_qmv.K == device.spec_hidden_K;
    const use_fused_silu =
        if (comptime Config.quant_format == .q4_mlx)
            !use_fused_norm_silu and can_fuse and
                device.spec_q4mv_fused_pair_silu_f16io !=
                    null and
                device.spec_q4mv_fused_pair_silu_f16io.?
                    .max_threads_per_group >= 512 and
                mlp_qmv.K == device.spec_q4_hidden_K
        else
            !use_fused_norm_silu and can_fuse and
                device.spec_qmv_fused_pair_silu_f16io !=
                    null and
                device.spec_qmv_fused_pair_silu_f16io.?
                    .max_threads_per_group >= 512 and
                mlp_qmv.K == device.spec_hidden_K;
    if (use_fused_norm_silu) {
        // Fused norm+gate+up+SiLU: reads f32 residual
        // directly, computes RMSNorm in TG memory, then
        // gate+up QMV with SiLU.  Skips norm_out, gate,
        // and up buffers entirely.
        if (comptime Config.quant_format == .q4_mlx) {
            dispatchQ4FusedNormPairSiLUf16io(
                device,
                encoder,
                a.gate_proj,
                a.up_proj,
                a.residual,
                a.mlp_out,
                a.ffn_norm_scale,
                mlp_qmv,
            );
        } else {
            dispatchFusedNormPairSiLUf16io(
                device,
                encoder,
                a.gate_proj,
                a.up_proj,
                a.residual,
                a.mlp_out,
                a.ffn_norm_scale,
                mlp_qmv,
            );
        }
    } else if (use_fused_silu) {
        // Fused gate+up+SiLU: needs separate RMSNorm first.
        dispatchRMSNorm(
            device,
            encoder,
            if (comptime Config.quant_format == .q4_mlx)
                pipelines.rms_norm_bf16_f16out
            else
                pipelines.rms_norm_f16out,
            a.residual,
            a.ffn_norm_scale,
            a.norm_out,
            .{
                .hidden_size = Config.hidden_size,
                .num_tokens = 1,
                .eps = 1e-6,
            },
        );
        bufferBarrier(encoder);
        if (comptime Config.quant_format == .q4_mlx) {
            dispatchQ4MVFusedPairSiLUf16io(
                device,
                encoder,
                a.gate_proj,
                a.up_proj,
                a.norm_out,
                a.mlp_out,
                mlp_qmv,
            );
        } else {
            dispatchQMVFusedPairSiLUf16io(
                device,
                encoder,
                a.gate_proj,
                a.up_proj,
                a.norm_out,
                a.mlp_out,
                mlp_qmv,
            );
        }
    } else {
        // Non-fused-norm paths need separate RMSNorm.
        dispatchRMSNorm(
            device,
            encoder,
            if (comptime Config.quant_format == .q4_mlx)
                pipelines.rms_norm_bf16_f16out
            else
                pipelines.rms_norm_f16out,
            a.residual,
            a.ffn_norm_scale,
            a.norm_out,
            .{
                .hidden_size = Config.hidden_size,
                .num_tokens = 1,
                .eps = 1e-6,
            },
        );
        bufferBarrier(encoder);
        if (comptime Config.quant_format == .q4_mlx) {
            if (can_fuse) {
                dispatchQ4MVFusedPairf16io(
                    device,
                    encoder,
                    a.gate_proj,
                    a.up_proj,
                    a.norm_out,
                    a.gate,
                    a.up,
                    mlp_qmv,
                );
                bufferBarrier(encoder);
                dispatchSiLUElementwiseMul(
                    device,
                    encoder,
                    pipelines.silu_elementwise_mul_f16,
                    a.gate,
                    a.up,
                    a.mlp_out,
                    Config.intermediate_size,
                );
            } else {
                dispatchQ4MVf16io(
                    device,
                    encoder,
                    a.gate_proj,
                    a.norm_out,
                    a.gate,
                    mlp_qmv,
                );
                dispatchQ4MVf16io(
                    device,
                    encoder,
                    a.up_proj,
                    a.norm_out,
                    a.up,
                    mlp_qmv,
                );
                bufferBarrier(encoder);
                dispatchSiLUElementwiseMul(
                    device,
                    encoder,
                    pipelines.silu_elementwise_mul_f16,
                    a.gate,
                    a.up,
                    a.mlp_out,
                    Config.intermediate_size,
                );
            }
        } else {
            if (can_fuse) {
                dispatchQMVFusedPairf16io(
                    device,
                    encoder,
                    a.gate_proj,
                    a.up_proj,
                    a.norm_out,
                    a.gate,
                    a.up,
                    mlp_qmv,
                );
                bufferBarrier(encoder);
                dispatchSiLUElementwiseMul(
                    device,
                    encoder,
                    pipelines.silu_elementwise_mul_f16,
                    a.gate,
                    a.up,
                    a.mlp_out,
                    Config.intermediate_size,
                );
            } else {
                dispatchQMVf16io(
                    device,
                    encoder,
                    a.gate_proj,
                    a.norm_out,
                    a.gate,
                    mlp_qmv,
                );
                dispatchQMVf16io(
                    device,
                    encoder,
                    a.up_proj,
                    a.norm_out,
                    a.up,
                    mlp_qmv,
                );
                bufferBarrier(encoder);
                dispatchSiLUElementwiseMul(
                    device,
                    encoder,
                    pipelines.silu_elementwise_mul_f16,
                    a.gate,
                    a.up,
                    a.mlp_out,
                    Config.intermediate_size,
                );
            }
        }
    }
    bufferBarrier(encoder);
    // Fused QMV + residual accumulate: the down-projection
    // result is added directly to the f32 residual instead of
    // writing f16 to proj_out then dispatching residual_add_f16.
    // Saves one dispatch + one barrier.
    const down_dims = QMVDims{
        .M = Config.hidden_size,
        .K = Config.intermediate_size,
        .group_size = Config.group_size,
    };
    if (comptime Config.quant_format == .q4_mlx) {
        dispatchQ4MVf16ioResadd(
            device,
            encoder,
            a.down_proj,
            a.mlp_out,
            a.residual,
            down_dims,
        );
    } else {
        dispatchQMVf16ioResadd(
            device,
            encoder,
            a.down_proj,
            a.mlp_out,
            a.residual,
            down_dims,
        );
    }
    bufferBarrier(encoder);
}

